const clientes = $('HTTPClientes').all();
const productos = $('HTTPProductos').all();

// Crear mapa de productos: descripcion -> precio
const mapaProductos = {};
productos.forEach(item => {
  const p = item.json;
  if (p.descripcion && p.precio !== undefined) {
    mapaProductos[p.descripcion.trim()] = p.precio;
  }
});

return clientes
  .filter(item => item !== null && item !== undefined)
  .map(item => {
    const cliente = item.json;
    const datos = {};
    const obs = cliente.observaciones || "";
    obs.split("|").forEach(par => {
      const [clave, valor] = par.split(":");
      if (clave && valor) {
        datos[clave.trim()] = valor.trim();
      }
    });

    const nombreProducto = datos["PRODUCTO"] || "";
    const precioBase = mapaProductos[nombreProducto] || 0;

    // Quitar ceros a la izquierda del ID Cliente
    const idClienteRaw = String(cliente.codcliente || "").trim();
    const idClienteLimpio = idClienteRaw.replace(/^0+/, "") || "0";

    return {
      json: {
        "Dominio":            datos["DOMINIO"]     || "",
        "Email Cliente":      cliente.email        || "",
        "Fecha Vencimiento":  datos["VENCIMIENTO"] || "",
        "Estado":             datos["ESTADO"]      || "Manual",
        "Producto":           nombreProducto,
        "Precio Base (€)":    precioBase,
        "ID Cliente":         idClienteLimpio,
        "Nombre Cliente":     cliente.nombre       || "",
        "Teléfono":           cliente.telefono1    || ""
      }
    };
  });

// Usamos la sintaxis $() que es más precisa para referenciar nodos previos
const recurrente = $("HTTPRecurrentes").first().json;
const cliente = $("HTTPClientes").first().json;
// OJO: He corregido el nombre basándome en tu lista de la izquierda
const linea = $("HTTPPrecurrenteslines").first().json;

const getDominio = (email) => {
  if (!email || typeof email !== 'string') return 'N/A';
  return email.split('@')[1] || 'N/A';
};

return [
  {
    json: {
      "Dominio": getDominio(cliente.email),
      "Email Cliente": cliente.email || "Sin email",
      "Fecha Vencimiento": recurrente.enddate || "N/A",
      "Estado": recurrente.idstatus === 7 ? "Activo" : (recurrente.idstatus || "N/A"),
      "Precio Base (€)": linea.price || 0,
      "ID Cliente": cliente.codcliente || recurrente.codcliente,
      "Nombre Cliente": cliente.razonsocial || cliente.nombre || "N/A",
      "Última Acción": recurrente.lastdate || "N/A"
    }
  }
];
